// Subsets II - with duplicates
public List<List<Integer>> subsetsWithDup(int[] nums) {
    List<List<Integer>> result = new ArrayList<>();
    Arrays.sort(nums);  // IMPORTANT: sort first
    backtrack(nums, 0, new ArrayList<>(), result);
    return result;
}

void backtrack(int[] nums, int start, List<Integer> path, List<List<Integer>> result) {
    result.add(new ArrayList<>(path));

    for (int i = start; i < nums.length; i++) {
        // Skip duplicates at the same level
        if (i > start && nums[i] == nums[i - 1]) continue;

        path.add(nums[i]);
        backtrack(nums, i + 1, path, result);
        path.remove(path.size() - 1);
    }
}

// Permutations II - with duplicates
public List<List<Integer>> permuteUnique(int[] nums) {
    List<List<Integer>> result = new ArrayList<>();
    Arrays.sort(nums);
    backtrackPerm(nums, new ArrayList<>(), new boolean[nums.length], result);
    return result;
}

void backtrackPerm(int[] nums, List<Integer> path, boolean[] used, List<List<Integer>> result) {
    if (path.size() == nums.length) {
        result.add(new ArrayList<>(path));
        return;
    }

    for (int i = 0; i < nums.length; i++) {
        // Skip if used OR if duplicate and previous not used
        if (used[i] || (i > 0 && nums[i] == nums[i - 1] && !used[i - 1])) continue;

        used[i] = true;
        path.add(nums[i]);
        backtrackPerm(nums, path, used, result);
        path.remove(path.size() - 1);
        used[i] = false;
    }
}

