function dijkstra(graph, n, start) {
    const dist = new Array(n).fill(Infinity);
    dist[start] = 0;
    const pq = [[0, start]];  // [distance, node]

    while (pq.length) {
        pq.sort((a, b) => a[0] - b[0]);
        const [d, u] = pq.shift();

        if (d > dist[u]) continue;  // Skip outdated

        for (let [v, w] of graph[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push([dist[v], v]);
            }
        }
    }
    return dist;
}

