public <T, K> Map<K, List<T>> groupByKey(
        List<T> items, Function<T, K> keyFn) {
    Map<K, List<T>> groups = new HashMap<>();
    for (T item : items) {
        K key = keyFn.apply(item);
        groups.computeIfAbsent(key, k -> new ArrayList<>()).add(item);
    }
    return groups;
}

