// Task Scheduler - Use max-heap for task frequency
function leastInterval(tasks, n) {
    const freq = new Map();
    for (const task of tasks) {
        freq.set(task, (freq.get(task) || 0) + 1);
    }

    const maxHeap = [...freq.values()].sort((a, b) => b - a);
    let time = 0;

    while (maxHeap.length > 0) {
        const temp = [];
        let cycle = n + 1;  // One cycle = n + 1 time units

        while (cycle > 0 && maxHeap.length > 0) {
            maxHeap.sort((a, b) => b - a);
            const count = maxHeap.shift();
            if (count > 1) temp.push(count - 1);
            time++;
            cycle--;
        }

        maxHeap.push(...temp);

        if (maxHeap.length > 0) {
            time += cycle;  // Add idle time
        }
    }
    return time;
}

