class UnionFindWithSize {
    int[] parent, size;
    int maxSize;

    UnionFindWithSize(int n) {
        parent = new int[n];
        size = new int[n];
        maxSize = 1;
        for (int i = 0; i < n; i++) {
            parent[i] = i;
            size[i] = 1;
        }
    }

    int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }

    boolean union(int x, int y) {
        int px = find(x), py = find(y);
        if (px == py) return false;

        // Union by size - attach smaller to larger
        if (size[px] < size[py]) {
            parent[px] = py;
            size[py] += size[px];
            maxSize = Math.max(maxSize, size[py]);
        } else {
            parent[py] = px;
            size[px] += size[py];
            maxSize = Math.max(maxSize, size[px]);
        }
        return true;
    }

    int getSize(int x) {
        return size[find(x)];
    }
}

